import{_ as a,o as t,c as i,ai as r}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"Splash Screen Rendering","description":"Procedural splash animation rendering pipeline — icosahedron mesh, beam particles, spectral wave field, and ANSI encoding.","frontmatter":{"title":"Splash Screen Rendering","description":"Procedural splash animation rendering pipeline — icosahedron mesh, beam particles, spectral wave field, and ANSI encoding.","outline":[2,3]},"headers":[],"relativePath":"cli/splash-rendering.md","filePath":"cli/splash-rendering.md","lastUpdated":0}'),s={name:"cli/splash-rendering.md"};function n(l,e,d,o,p,h){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="splash-screen-rendering-pipeline" tabindex="-1">Splash Screen Rendering Pipeline <a class="header-anchor" href="#splash-screen-rendering-pipeline" aria-label="Permalink to “Splash Screen Rendering Pipeline”">​</a></h1><p>The splash screen (<code>splash/splash.go</code>) is a fully procedural animation rendered to ANSI true-color.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to “Components”">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Parameters</th><th>Description</th></tr></thead><tbody><tr><td>Icosahedron mesh</td><td>444 verts, 360 faces, pos(0.36, 0.50), scale 0.11</td><td>Rotating 3D wireframe mesh</td></tr><tr><td>Beam particles</td><td>200 particles, 4 rays, width 0.015</td><td>Horizontal light beam</td></tr><tr><td>Spectral wave field</td><td>freq 34.0/26.0, speed 1.0</td><td>Background wave pattern</td></tr><tr><td>Title</td><td>&quot;P R I S M&quot;</td><td>Centered text in near-white</td></tr><tr><td>Gradient bar</td><td>4-stop spectrum gradient</td><td>Horizontal bar below title</td></tr></tbody></table><h2 id="spectral-gradient-used-throughout" tabindex="-1">Spectral Gradient (used throughout) <a class="header-anchor" href="#spectral-gradient-used-throughout" aria-label="Permalink to “Spectral Gradient (used throughout)”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>#3B82F6 ───▶ #14B8A6 ───▶ #22C55E ───▶ #F59E0B</span></span>
<span class="line"><span> Blue          Teal         Green        Amber</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="ascii-density-ramp" tabindex="-1">ASCII Density Ramp <a class="header-anchor" href="#ascii-density-ramp" aria-label="Permalink to “ASCII Density Ramp”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{ &#39; &#39;, &#39;.&#39;, &#39;,&#39;, &#39;:&#39;, &#39;-&#39;, &#39;=&#39;, &#39;+&#39;, &#39;*&#39;, &#39;#&#39;, &#39;%&#39;, &#39;@&#39; }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>11 characters from empty to full density, used for wave field and mesh rendering.</p><h2 id="rendering-phases" tabindex="-1">Rendering Phases <a class="header-anchor" href="#rendering-phases" aria-label="Permalink to “Rendering Phases”">​</a></h2><ol><li>Rotate and project 444 mesh vertices (Y/X/Z rotation + perspective distance 3.5)</li><li>Rasterize 360 triangles with barycentric interpolation + back-face culling</li><li>Build beam light grid from particle positions with Gaussian glow</li><li>Compute layout for title, bar, and subtitle (centered)</li><li>Per-cell compositing: wave field + beam particles + mesh overlay + halo dimming</li><li>Stamp title (232, 232, 240 near-white)</li><li>Stamp gradient bar</li><li>Stamp subtitle with atmospheric offset</li><li>Convert to ANSI string (batch same-color runs, reset per line)</li></ol>`,11)])])}const g=a(s,[["render",n]]);export{m as __pageData,g as default};
